    .where({ supplier_code: value })
    .get()
    .then(response => {
        const matchingSuppliers = response.data || [];

        if (matchingSuppliers.length === 0) {
            callback();
            return;
        }

        if (page_status === 'Edit') {
            const currentSupplierID = this.getParamsVariables('supplier_no');
            const isSameSupplier = matchingSuppliers.some(supplier => supplier.id === currentSupplierID);
            callback(isSameSupplier ? undefined : 'Supplier ID already exists.');
        } else {
            callback('Supplier ID already exists.');
        }
    })
    .catch(error => {
        console.error("Error checking supplier:", error);
        callback("Error validating supplier ID.");
    });

