  if (status !== "Draft" && status !== "Issued") {
    this.disabled(
      [
        "purchase_order_no",
        "po_supplier_id",
        "organization_id",
        "po_date",
        "po_currency",
        "po_delivery_address",
        "po_plant",
        "po_receiving_supplier",
        "po_billing_name",
        "po_billing_cp",
        "po_billing_address",
        "po_shipping_address",
        "po_payment_terms",
        "po_expected_date",
        "po_shipping_preference",
        "po_ref_doc",
        "table_po",
        "po_total_gross",
        "po_total_discount",
        "po_total_tax",
        "po_total",
        "po_remark",
        "po_remark2",
        "po_remark3",
        "po_remark4",
        "po_remark5",
        "po_tnc",
        "billing_address_line_1",
        "billing_address_line_2",
        "billing_address_line_3",
        "billing_address_line_4",
        "billing_address_city",
        "billing_postal_code",
        "billing_address_state",
        "billing_address_country",
        "shipping_address_line_1",
        "shipping_address_line_2",
        "shipping_address_line_3",
        "shipping_address_line_4",
        "shipping_address_city",
        "shipping_postal_code",
        "shipping_address_state",
        "shipping_address_country",
        "exchange_rate",
        "myr_total_amount",
      ],
      true,
    );

    this.hide([
      "link_billing_address",
      "link_shipping_address",
      "button_save_as_draft",
      "button_save_as_issue",
    ]);
  } else if (status === "Issued") {
    this.hide("button_save_as_draft");
  }
};

const cloneResetQuantity = async (data) => {
  const tablePO = this.getValue("table_po");

  for (const po of tablePO) {
    po.received_qty = 0;
    po.return_quantity = 0;
    po.invoice_qty = 0;
    po.posted_qty = 0;
    po.min_price = 0;
    po.max_price = 0;
    po.outstanding_quantity = 0;
    po.preq_id = "";
    po.line_status = "";
    po.pi_status = "";
  }

  data["table_po"] = tablePO;
  data["gr_status"] = "";
  data["pi_posted_status"] = "";
  data["pi_status"] = "";
  data["return_status"] = "";
  data["partially_received"] = `0 / ${tablePO.length}`;
  data["fully_received"] = `0 / ${tablePO.length}`;
  data["po_date"] = new Date().toISOString().split("T")[0];
  data["po_status"] = "Draft";
  data["preq_no"] = "";
  data["preq_id"] = [];
  data["purchase_order_no"] = null;

  this.hide("preq_no");

  return data;
};

const setPlant = async (organizationId, pageStatus, data) => {
  const currentDept = this.getVarSystem("deptIds");

  if (currentDept === organizationId) {
    this.disabled("po_plant", false);

    if (pageStatus === "Add" || pageStatus === "Clone") {
      this.setData({"po_plant":currentDept});
    }
  } else {
    if (pageStatus === "Add" || pageStatus === "Clone") {
      this.setData({"po_plant":currentDept});
    }
    this.disabled("po_plant", true);
  }

  return data;
};

const checkAccIntegrationType = async (organizationId, data) => {
  if (organizationId) {
    const resAI = await db
      .collection("accounting_integration")
      .where({ organization_id: organizationId })
      .get();

    if (resAI && resAI.data.length > 0) {
      const aiData = resAI.data[0];
      data["acc_integration_type"] = aiData.acc_integration_type;
    }
  }

  return data;
};

(async () => {
  try {
    const status = await this.getValue("po_status");
    const data = {};
    const pageStatus = this.isAdd
      ? "Add"
      : this.isEdit
        ? "Edit"
        : this.isView
          ? "View"
          : this.isCopy
            ? "Clone"
            : (() => {
                this.$message.error("Invalid page status");
              })();

    let organizationId = this.getVarGlobal("deptParentId");
    if (organizationId === "0") {
      organizationId = this.getVarSystem("deptIds");
    }
    data["page_status"] = pageStatus;
    this.hide([
      "exchange_rate",
      "exchange_rate_myr",
      "exchange_rate_currency",
      "myr_total_amount",
      "total_amount_myr",
    ]);
    const tabGR = document.getElementById("tab-tab_gr");

    switch (pageStatus) {
      case "Add":
        this.display(["draft_status"]);
        const supplierID = this.getValue("po_supplier_id");
        this.disabled("table_po", !supplierID);
        data["organization_id"] = organizationId;
        data["po_date"] = new Date().toISOString().split("T")[0];

        // hide GR Tab
        if (tabGR) {
          tabGR.style.display = "none";
        }
        await setPlant(organizationId, pageStatus, data);
        await checkAccIntegrationType(organizationId, data);
        await enabledUOMField();
        await displayFields();
        await displayCurrency();
        await displayPlantAddress();
        await displayTax();
        break;

      case "Edit":
        await disabledEditField(status);
        await showStatusHTML(status);
        await checkAccIntegrationType(organizationId, data);
        await enabledUOMField();
        await displayFields();
        await displayCurrency();
        await displayPlantAddress();
        await displayTax();
        await setPlant(organizationId, pageStatus, data);
        data["previous_status"] = this.getValue("po_status");
        this.disabled(
          status !== "Draft"
            ? ["purchase_order_no", "purchase_order_no_type"]
            : [],
          true,
        );

        // hide GR Tab
        if (tabGR) {
          tabGR.style.display = "none";
        }
        break;

      case "Clone":
        // hide GR Tab
        if (tabGR) {
          tabGR.style.display = "none";
        }
        await displayFields();
        await checkAccIntegrationType(organizationId, data);
        await setPlant(organizationId, pageStatus, data);
        await enabledUOMField();
        await displayCurrency();
        await displayPlantAddress();
        await displayTax();
        await showStatusHTML("Draft");
        await cloneResetQuantity(data);

        break;

      case "View":
        this.hide([
          "link_billing_address",
          "link_shipping_address",
          "button_save_as_draft",
          "button_save_as_issue",
        ]);

        // hide GR Tab
        if (tabGR && status !== "Processing") {
          tabGR.style.display = "none";
        }
        await showStatusHTML(status);
        await displayFields();
        await displayCurrency();
        await displayPlantAddress();
        await displayTax();

        break;
    }

    this.setData(data);
    this.refreshFieldOptionData('po_plant')
  } catch (error) {
    this.$message.error(error);
  }
})();

setTimeout(async () => {
  const maxRetries = 10;
  const interval = 500;
  for (let i = 0; i < maxRetries; i++) {
    const op = await this.onDropdownVisible("purchase_order_no_type", true);
    if (op != null) break;
    await new Promise((resolve) => setTimeout(resolve, interval));
  }
  function getDefaultItem(arr) {
    return arr?.find((item) => item?.item?.is_default === 1);
  }
  var params = this.getComponent("purchase_order_no");
  const { options } = params;

  const optionsData = this.getOptionData("purchase_order_no_type") || [];
  const defaultData = getDefaultItem(optionsData);
  if (options?.canManualInput) {
    this.setOptionData("purchase_order_no_type", [
      { label: "Manual Input", value: -9999 },
      ...optionsData,
    ]);
    if (this.isAdd) {
      this.setData({
        purchase_order_no_type: defaultData ? defaultData.value : -9999,
      });
    }
  } else if (defaultData) {
    if (this.isAdd) {
      this.setData({ purchase_order_no_type: defaultData.value });
    }
  }
}, 200);

const fetchLatestPricing = async (result, overwrite) => {
  for (const item of result) {
    if (overwrite === "Yes") {
      updates[`table_po.${item.line_index}.unit_price`] = item.unit_price;
      updates[`table_po.${item.line_index}.quantity_uom`] = item.uom_id;
      updates[`table_po.${item.line_index}.tax_preference`] = item.tax_rate;
      updates[`table_po.${item.line_index}.tax_percent`] = item.tax_percent;
      updates[`table_po.${item.line_index}.from_historical`] =
        item.from_historical;
      updates[`table_po.${item.line_index}.quantity`] = item.quantity;
      updates[`table_po.${item.line_index}.discount`] = item.discount;
      updates[`table_po.${item.line_index}.discount_uom`] = item.discount_uom;
    }

    updates[`table_po.${item.line_index}.max_price`] = item.max_price;
    updates[`table_po.${item.line_index}.min_price`] = item.min_price;
    updates[`table_po.${item.line_index}.moq_qty`] = item.moq;
  }

  await this.setData(updates);
  await this.triggerEvent("POcalculation");
};

(async () => {
  console.log(arguments[0]);

  this.disabled("table_po", !arguments[0].value);

  const tablePO = this.getValue("table_po");

  if (tablePO.length > 0 && arguments[0].value) {
    const hasItemID = tablePO.some((item) => item.item_id);
    const plantID = this.getValue("po_plant");
    if (hasItemID) {
      await this.runWorkflow(
        "2067818102244966401",
        {
          document_type: "PO",
          supp_cust_id: supplierID,
          plant_id: plantID,
          item_data: tablePO.map((item, index) => {
            return {
              item_id: item.item_id,
              unit_price: item.unit_price,
              line_index: index,
              uom_id: item.quantity_uom,
              tax_rate: item.tax_preference || null,
              tax_percent: item.tax_percent || null,
              quantity: item.quantity,
              discount: item.discount,
              discount_uom: item.discount_uom,
            };
          }),
        },
        async (result) => {
          console.log("result", result);
          const updates = {};

          if (result.data.needOverwrite === "No") return;

          await this.$confirm(
            `The supplier has been changed. Please choose one: <br><br>Please choose one: <br>
        <strong>Overwrite:</strong> Replace the price based on the latest supplier. <em>(If any)</em><br>
        <strong>Keep:</strong> Keep the existing item price.`,
            "Supplier Change Detected",
            {
              confirmButtonText: "Overwrite",
              cancelButtonText: "Keep",
              dangerouslyUseHTMLString: true,
              type: "info",
              distinguishCancelAndClose: true,

              beforeClose: async (action, instance, done) => {
                if (action === "confirm") {
                  await fetchLatestPricing(result.data.data, "Yes");

                  done();
                } else if (action === "cancel") {
                  await fetchLatestPricing(result.data.data, "No");

                  done();
                } else {
                  done();
                }
              },
            },
          );
        },
        (error) => {
          console.log("error", error);
        },
      );
    }
  }

  const currencyID = arguments[0].fieldModel.item.currency_id;
  const paymentTermID = arguments[0].fieldModel.item.supplier_payment_term_id;
  const priceTagID = arguments[0].fieldModel.item.price_tag_id;

  const resCurrency = await db
    .collection("currency")
    .where({ id: currencyID })
    .get();

  const currencyEntry = await resCurrency.data[0];
  const currencyCode = await currencyEntry.currency_code;

  if (!currencyCode) {
    this.hide([
      "exchange_rate",
      "exchange_rate_myr",
      "exchange_rate_currency",
      "myr_total_amount",
      "total_amount_myr",
    ]);
    return;
  } else {
    this.setData({
      total_gross_currency: currencyCode,
      total_discount_currency: currencyCode,
      total_tax_currency: currencyCode,
      total_amount_currency: currencyCode,
      exchange_rate_currency: currencyCode,
    });

    if (currencyCode !== "----" && currencyCode !== "MYR") {
      this.setData({ exchange_rate: currencyEntry.currency_buying_rate });

      this.display([
        "exchange_rate",
        "exchange_rate_myr",
        "exchange_rate_currency",
        "myr_total_amount",
        "total_amount_myr",
      ]);
    } else {
      this.setData({ exchange_rate: 1 });
      this.hide([
        "exchange_rate",
        "exchange_rate_myr",
        "exchange_rate_currency",
        "myr_total_amount",
        "total_amount_myr",
      ]);
    }
  }

  this.setData({
    po_payment_terms: paymentTermID,
    price_tag_id: priceTagID,
    po_currency: currencyCode,
  });
})();

const resetData = async (rowIndex) => {
  this.setData({
    [`table_po.${rowIndex}.item_name`]: "",
    [`table_po.${rowIndex}.item_desc`]: "",
    [`table_po.${rowIndex}.quantity`]: 0,
    [`table_po.${rowIndex}.quantity_uom`]: "",
    [`table_po.${rowIndex}.unit_price`]: 0,
    [`table_po.${rowIndex}.gross`]: 0,
    [`table_po.${rowIndex}.discount`]: 0,
    [`table_po.${rowIndex}.discount_uom`]: "",
    [`table_po.${rowIndex}.discount_amount`]: 0,
    [`table_po.${rowIndex}.tax_preference`]: "",
    [`table_po.${rowIndex}.tax_percent`]: "",
    [`table_po.${rowIndex}.tax_amount`]: 0,
    [`table_po.${rowIndex}.tax_inclusive`]: 0,
    [`table_po.${rowIndex}.po_amount`]: 0,
    [`table_po.${rowIndex}.received_qty`]: 0,
    [`table_po.${rowIndex}.return_quantity`]: 0,
    [`table_po.${rowIndex}.item_category_id`]: "",
    [`table_po.${rowIndex}.table_uom_conversion`]: "",
    [`table_po.${rowIndex}.alt_uom`]: "",
  });
};

(async () => {
  const rowIndex = arguments[0].rowIndex;
  const poItem = arguments[0].poItem;
  const supplierID = this.getValue("po_supplier_id");
  const plantID = this.getValue("po_plant");

  console.log("arguments line item", arguments[0]);
  if (arguments[0].fieldModel && !poItem) {
    console.log("arguments line item reset", arguments[0].fieldModel);
    console.log("arguments line item reset", poItem);
    await resetData(rowIndex);

    await this.runWorkflow(
      "2067818102244966401",
      {
        document_type: "PO",
        supp_cust_id: supplierID,
        plant_id: plantID,
        item_data: [
          {
            item_id: arguments[0].value,
            line_index: rowIndex,
            uom_id:
              arguments[0].fieldModel.item.purchase_default_uom ||
              arguments[0].fieldModel.item.based_uom,
          },
        ],
      },
      async (result) => {
        console.log("result", result);
        const updates = {};

        for (const item of result.data.data) {
